-      channelAllowlistConfigured,
-      channelAllowed,
-    })
-  ) {
-    await replyUnauthorized();
-    return false;
-  }
-  if (channelConfig?.allowed === false) {
-    await replyUnauthorized();
-    return false;
-  }
-
-  const { memberAllowed } = resolveDiscordMemberAccessState({
